#define BLOCK_SIZE 16

const float amb_temp = 80.0f;

__kernel void hotspot(
    const int num_iterations,
    const __global const float *power,
    const __global float *temp,
    __global float *result,
    const int col,
    const int row,
    const int borderCols,
    const int borderRows,
    const float Cap,
    const float Rx,
    const float Ry,
    const float Rz,
    const float step)
{
    float Cap_1 = step / Cap;
    float Rx_1 = 1.0f / Rx;
    float Ry_1 = 1.0f / Ry;
    float Rz_1 = 1.0f / Rz;

    int c_start = __get_global_id(0) * BLOCK_SIZE;
    int r_start = __get_global_id(1) * BLOCK_SIZE;

    int local_c = __get_local_id(0);
    int local_r = __get_local_id(1);

    int c_end = c_start + BLOCK_SIZE;
    int r_end = r_start + BLOCK_SIZE;

    if (c_end > col) c_end = col;
    if (r_end > row) r_end = row;

    // Use local memory for the block to support multiple iterations without global races
    __local float local_temp[BLOCK_SIZE][BLOCK_SIZE];
    __local float local_power[BLOCK_SIZE][BLOCK_SIZE];

    int global_c = c_start + local_c;
    int global_r = r_start + local_r;

    // Load data into local memory
    if (global_r < row && global_c < col) {
        local_temp[local_r][local_c] = temp[global_r * col + global_c];
        local_power[local_r][local_c] = power[global_r * col + global_c];
    } else {
        local_temp[local_r][local_c] = 0.0f;
        local_power[local_r][local_c] = 0.0f;
    }

    __barrier(CLK_LOCAL_MEM_FENCE);

    // Perform iterations
    for (int iter = 0; iter < num_iterations; iter++) {
        // Compute update for each cell in the block
        if (global_r < row && global_c < col) {
            float t_curr = local_temp[local_r][local_c];
            float p_curr = local_power[local_r][local_c];
            float delta;

            // Boundary checks based on global coordinates
            if (global_r == 0 && global_c == 0) {
                float t_right = (local_c + 1 < BLOCK_SIZE) ? local_temp[local_r][local_c + 1] : t_curr;
                float t_down  = (local_r + 1 < BLOCK_SIZE) ? local_temp[local_r + 1][local_c] : t_curr;
                delta = Cap_1 * (p_curr + 
                    (t_right - t_curr) * Rx_1 + 
                    (t_down - t_curr) * Ry_1 + 
                    (amb_temp - t_curr) * Rz_1);
            }
            else if (global_r == 0 && global_c == col - 1) {
                float t_left = (local_c - 1 >= 0) ? local_temp[local_r][local_c - 1] : t_curr;
                float t_down = (local_r + 1 < BLOCK_SIZE) ? local_temp[local_r + 1][local_c] : t_curr;
                delta = Cap_1 * (p_curr + 
                    (t_left - t_curr) * Rx_1 + 
                    (t_down - t_curr) * Ry_1 + 
                    (amb_temp - t_curr) * Rz_1);
            }
            else if (global_r == row - 1 && global_c == col - 1) {
                float t_left = (local_c - 1 >= 0) ? local_temp[local_r][local_c - 1] : t_curr;
                float t_up   = (local_r - 1 >= 0) ? local_temp[local_r - 1][local_c] : t_curr;
                delta = Cap_1 * (p_curr + 
                    (t_left - t_curr) * Rx_1 + 
                    (t_up - t_curr) * Ry_1 + 
                    (amb_temp - t_curr) * Rz_1);
            }
            else if (global_r == row - 1 && global_c == 0) {
                float t_right = (local_c + 1 < BLOCK_SIZE) ? local_temp[local_r][local_c + 1] : t_curr;
                float t_up    = (local_r - 1 >= 0) ? local_temp[local_r - 1][local_c] : t_curr;
                delta = Cap_1 * (p_curr + 
                    (t_right - t_curr) * Rx_1 + 
                    (t_up - t_curr) * Ry_1 + 
                    (amb_temp - t_curr) * Rz_1);
            }
            else if (global_r == 0) {
                float t_right = (local_c + 1 < BLOCK_SIZE) ? local_temp[local_r][local_c + 1] : t_curr;
                float t_left  = (local_c - 1 >= 0) ? local_temp[local_r][local_c - 1] : t_curr;
                float t_down  = (local_r + 1 < BLOCK_SIZE) ? local_temp[local_r + 1][local_c] : t_curr;
                delta = Cap_1 * (p_curr + 
                    (t_right + t_left - 2.0f * t_curr) * Rx_1 + 
                    (t_down - t_curr) * Ry_1 + 
                    (amb_temp - t_curr) * Rz_1);
            }
            else if (global_c == col - 1) {
                float t_up    = (local_r - 1 >= 0) ? local_temp[local_r - 1][local_c] : t_curr;
                float t_down  = (local_r + 1 < BLOCK_SIZE) ? local_temp[local_r + 1][local_c] : t_curr;
                float t_left  = (local_c - 1 >= 0) ? local_temp[local_r][local_c - 1] : t_curr;
                delta = Cap_1 * (p_curr + 
                    (t_up + t_down - 2.0f * t_curr) * Ry_1 + 
                    (t_left - t_curr) * Rx_1 + 
                    (amb_temp - t_curr) * Rz_1);
            }
            else if (global_r == row - 1) {
                float t_right = (local_c + 1 < BLOCK_SIZE) ? local_temp[local_r][local_c + 1] : t_curr;
                float t_left  = (local_c - 1 >= 0) ? local_temp[local_r][local_c - 1] : t_curr;
                float t_up    = (local_r - 1 >= 0) ? local_temp[local_r - 1][local_c] : t_curr;
                delta = Cap_1 * (p_curr + 
                    (t_right + t_left - 2.0f * t_curr) * Rx_1 + 
                    (t_up - t_curr) * Ry_1 + 
                    (amb_temp - t_curr) * Rz_1);
            }
            else if (global_c == 0) {
                float t_up    = (local_r - 1 >= 0) ? local_temp[local_r - 1][local_c] : t_curr;
                float t_down  = (local_r + 1 < BLOCK_SIZE) ? local_temp[local_r + 1][local_c] : t_curr;
                float t_right = (local_c + 1 < BLOCK_SIZE) ? local_temp[local_r][local_c + 1] : t_curr;
                delta = Cap_1 * (p_curr + 
                    (t_up + t_down - 2.0f * t_curr) * Ry_1 + 
                    (t_right - t_curr) * Rx_1 + 
                    (amb_temp - t_curr) * Rz_1);
            }
            else {
                float t_up    = local_temp[local_r - 1][local_c];
                float t_down  = local_temp[local_r + 1][local_c];
                float t_right = local_temp[local_r][local_c + 1];
                float t_left  = local_temp[local_r][local_c - 1];
                delta = Cap_1 * (p_curr + 
                    (t_up + t_down - 2.0f * t_curr) * Ry_1 + 
                    (t_right + t_left - 2.0f * t_curr) * Rx_1 + 
                    (amb_temp - t_curr) * Rz_1);
            }

            local_temp[local_r][local_c] = t_curr + delta;
        }

        __barrier(CLK_LOCAL_MEM_FENCE);
    }

    // Write result back to global memory
    if (global_r < row && global_c < col) {
        result[global_r * col + global_c] = local_temp[local_r][local_c];
    }
}
